export const name = "repo";
export const version = "0.1.0";
export const description = "";

export function getIdentity() {
  return { name, version, description };
}

export function slugify(input) {
  const s = toStr(input).trim();
  if (!s) return '';
  const normalized = s.normalize ? s.normalize('NFKD') : s;
  const noMarks = normalized.replace(/\p{M}/gu, '');
  const replaced = noMarks.replace(/[^\p{L}\p{N}]+/gu, '-');
  return replaced.replace(/^-+|-+$/g, '').toLowerCase();
}

export function truncate(input, maxLength = 30, ellipsis = '...') {
  const s = toStr(input);
  const chars = Array.from(s);
  if (maxLength <= 0) return '';
  if (chars.length <= maxLength) return s;
  const keep = Math.max(1, maxLength - ellipsis.length);
  return chars.slice(0, keep).join('') + ellipsis;
}

export function camelCase(input) {
  const s = toStr(input);
  if (!s) return '';
  const withSpaces = s.replace(/([a-z0-9])([A-Z])/g, '$1 $2').replace(/[_\-\s]+/g, ' ').trim();
  const parts = withSpaces.split(/\s+/).filter(Boolean);
  if (!parts.length) return '';
  const [first, ...rest] = parts;
  return first.toLowerCase() + rest.map((p) => p.charAt(0).toUpperCase() + p.slice(1).toLowerCase()).join('');
}

export function kebabCase(input) {
  const s = toStr(input);
  if (!s) return '';
  const normalized = s.normalize ? s.normalize('NFKD') : s;
  const noMarks = normalized.replace(/\p{M}/gu, '');
  const spaced = noMarks.replace(/([a-z0-9])([A-Z])/g, '$1 $2').replace(/[^\p{L}\p{N}]+/gu, ' ').trim();
  return spaced.split(/\s+/).filter(Boolean).map((p) => p.toLowerCase()).join('-');
}

export function titleCase(input) {
  const s = toStr(input).trim();
  if (!s) return '';
  return s.toLowerCase().split(/\s+/).filter(Boolean).map((w) => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');
}

export function wordWrap(input, width = 80) {
  const s = toStr(input);
  if (s === '') return '';
  if (width <= 0) return s;
  const words = s.split(/\s+/);
  const lines = [];
  let line = '';
  for (const w of words) {
    if (!line) {
      if (strLen(w) > width) {
        const chars = Array.from(w);
        for (let i = 0; i < chars.length; i += width) lines.push(chars.slice(i, i + width).join(''));
      } else {
        line = w;
      }
    } else {
      if (strLen(line) + 1 + strLen(w) <= width) line = line + ' ' + w;
      else {
        lines.push(line);
        if (strLen(w) > width) {
          const chars = Array.from(w);
          for (let i = 0; i < chars.length; i += width) lines.push(chars.slice(i, i + width).join(''));
          line = '';
        } else line = w;
      }
    }
  }
  if (line) lines.push(line);
  return lines.join('\n');
}

export function stripHtml(input) {
  let s = toStr(input);
  if (!s) return '';
  s = s.replace(/<[^>]*>/g, '');
  const entities = { nbsp: ' ', amp: '&', lt: '<', gt: '>', quot: '"', '#39': "'" };
  s = s.replace(/&(#x?[0-9a-fA-F]+|[a-zA-Z]+);/g, (match, token) => {
    if (token[0] === '#') {
      if (token[1] === 'x' || token[1] === 'X') return String.fromCharCode(parseInt(token.slice(2), 16));
      return String.fromCharCode(parseInt(token.slice(1), 10));
    }
    return entities[token] ?? match;
  });
  return s;
}

export function escapeRegex(input) {
  const s = toStr(input);
  return s.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

export function pluralize(word, count = null) {
  if (word == null) return '';
  const s = String(word);
  if (typeof count === 'number') return count === 1 ? s : pluralize(s);
  const lower = s.toLowerCase();
  const irregular = { person: 'people', man: 'men', woman: 'women', child: 'children', tooth: 'teeth', foot: 'feet', mouse: 'mice', goose: 'geese', ox: 'oxen', louse: 'lice' };
  if (irregular[lower]) return irregular[lower];
  if (/[sxz]$/i.test(s) || /(?:ch|sh)$/i.test(s)) return s + 'es';
  if (/[^aeiou]y$/i.test(s)) return s.slice(0, -1) + 'ies';
  if (/(?:f|fe)$/i.test(s)) return s.replace(/(f|fe)$/i, 'ves');
  return s + 's';
}

export function levenshtein(a, b) {
  const s = toStr(a);
  const t = toStr(b);
  const sChars = Array.from(s);
  const tChars = Array.from(t);
  const n = sChars.length;
  const m = tChars.length;
  if (n === 0) return m;
  if (m === 0) return n;
  const v0 = new Array(m + 1);
  const v1 = new Array(m + 1);
  for (let j = 0; j <= m; j++) v0[j] = j;
  for (let i = 0; i < n; i++) {
    v1[0] = i + 1;
    for (let j = 0; j < m; j++) {
      const cost = sChars[i] === tChars[j] ? 0 : 1;
      v1[j + 1] = Math.min(v1[j] + 1, v0[j + 1] + 1, v0[j] + cost);
    }
    for (let j = 0; j <= m; j++) v0[j] = v1[j];
  }
  return v1[m];
}

export function resolveLocalRefs(schema) {
  if (!schema || typeof schema !== 'object') return schema;
  const root = deepClone(schema);
  const cache = new Map();

  function _resolve(node, seen = new Set()) {
    if (Array.isArray(node)) return node.map((n) => _resolve(n, seen));
    if (!node || typeof node !== 'object') return node;
    if (node.$ref && typeof node.$ref === 'string') {
      const ref = node.$ref;
      if (!ref.startsWith('#')) throw new Error('Remote $ref not supported: ' + ref);
      if (cache.has(ref)) return deepClone(cache.get(ref));
      if (seen.has(ref)) return { $ref: ref }; // circular, return pointer to avoid infinite recursion
      seen.add(ref);
      const referenced = getByJsonPointer(root, ref);
      if (referenced === undefined) throw new Error('Unresolved local $ref: ' + ref);
      const resolved = _resolve(deepClone(referenced), seen);
      cache.set(ref, resolved);
      seen.delete(ref);
      return deepClone(resolved);
    }
    const out = {};
    for (const k of Object.keys(node)) out[k] = _resolve(node[k], seen);
    return out;
  }

  return _resolve(root, new Set());
}

export function diffSchemas(schemaA, schemaB) {
  if (!schemaA || !schemaB) throw new Error('Both schemas must be provided');
  const a = resolveLocalRefs(schemaA);
  const b = resolveLocalRefs(schemaB);

  function diffSubschemas(aNode = {}, bNode = {}, path = '/') {
    const changes = [];

    // description change
    if ((aNode.description || '') !== (bNode.description || '')) {
      changes.push({ path: makePath(path, 'description'), changeType: 'description-changed', before: aNode.description ?? null, after: bNode.description ?? null });
    }

    // type change
    if (JSON.stringify(aNode.type ?? null) !== JSON.stringify(bNode.type ?? null)) {
      changes.push({ path: path, changeType: 'type-changed', before: aNode.type ?? null, after: bNode.type ?? null });
    }

    // enum
    const aEnum = ensureArray(aNode.enum);
    const bEnum = ensureArray(bNode.enum);
    for (const v of bEnum.filter((x) => !aEnum.includes(x))) changes.push({ path: makePath(path, 'enum'), changeType: 'enum-value-added', before: null, after: v });
    for (const v of aEnum.filter((x) => !bEnum.includes(x))) changes.push({ path: makePath(path, 'enum'), changeType: 'enum-value-removed', before: v, after: null });

    // properties
    const aProps = aNode.properties && typeof aNode.properties === 'object' ? aNode.properties : {};
    const bProps = bNode.properties && typeof bNode.properties === 'object' ? bNode.properties : {};
    const aReq = ensureArray(aNode.required);
    const bReq = ensureArray(bNode.required);

    const allKeys = Array.from(new Set([...Object.keys(aProps), ...Object.keys(bProps)]));
    for (const key of allKeys) {
      const propPath = makePath(path, `properties/${key}`);
      if (key in aProps && !(key in bProps)) {
        changes.push({ path: propPath, changeType: 'property-removed', before: deepClone(aProps[key]), after: null, wasRequired: aReq.includes(key) });
      } else if (!(key in aProps) && key in bProps) {
        changes.push({ path: propPath, changeType: 'property-added', before: null, after: deepClone(bProps[key]), isRequired: bReq.includes(key) });
      } else {
        const nested = diffSubschemas(aProps[key], bProps[key], propPath);
        if (nested.length) changes.push({ path: propPath, changeType: 'nested-changed', changes: nested });
      }
    }

    // required changes
    for (const added of bReq.filter((r) => !aReq.includes(r))) {
      changes.push({ path: makePath(path, `required/${added}`), changeType: 'required-added', before: false, after: true });
    }
    for (const removed of aReq.filter((r) => !bReq.includes(r))) {
      changes.push({ path: makePath(path, `required/${removed}`), changeType: 'required-removed', before: true, after: false });
    }

    // items
    if (aNode.items || bNode.items) {
      const aItems = aNode.items ?? null;
      const bItems = bNode.items ?? null;
      const itemsPath = makePath(path, 'items');
      if (!aItems && bItems) changes.push({ path: itemsPath, changeType: 'items-added', before: null, after: deepClone(bItems) });
      else if (aItems && !bItems) changes.push({ path: itemsPath, changeType: 'items-removed', before: deepClone(aItems), after: null });
      else if (aItems && bItems) {
        const nested = diffSubschemas(aItems, bItems, itemsPath);
        if (nested.length) changes.push({ path: itemsPath, changeType: 'nested-changed', changes: nested });
      }
    }

    // combinators
    for (const comb of ['allOf', 'oneOf', 'anyOf']) {
      const aComb = Array.isArray(aNode[comb]) ? aNode[comb] : [];
      const bComb = Array.isArray(bNode[comb]) ? bNode[comb] : [];
      const max = Math.max(aComb.length, bComb.length);
      for (let i = 0; i < max; i++) {
        const aC = aComb[i];
        const bC = bComb[i];
        const combPath = makePath(path, `${comb}/${i}`);
        if (aC && !bC) changes.push({ path: combPath, changeType: `${comb}-removed`, before: deepClone(aC), after: null });
        else if (!aC && bC) changes.push({ path: combPath, changeType: `${comb}-added`, before: null, after: deepClone(bC) });
        else if (aC && bC) {
          const nested = diffSubschemas(aC, bC, combPath);
          if (nested.length) changes.push({ path: combPath, changeType: 'nested-changed', changes: nested });
        }
      }
    }

    return changes;
  }

  return diffSubschemas(a, b, '/');
}

export function classifyChange(change) {
  if (!change || typeof change !== 'object') return 'informational';
  const t = change.changeType;
  if (t === 'property-added') return change.isRequired ? 'breaking' : 'compatible';
  if (t === 'property-removed') return change.wasRequired ? 'breaking' : 'compatible';
  if (t === 'required-added') return 'breaking';
  if (t === 'required-removed') return 'compatible';
  if (t === 'type-changed') return 'breaking';
  if (t === 'enum-value-removed') return 'breaking';
  if (t === 'enum-value-added') return 'compatible';
  if (t === 'description-changed') return 'informational';
  if (t === 'nested-changed') {
    const nested = Array.isArray(change.changes) ? change.changes : [];
    let worst = 'informational';
    for (const c of nested) {
      const cls = classifyChange(c);
      if (cls === 'breaking') return 'breaking';
      if (cls === 'compatible') worst = 'compatible';
    }
    return worst;
  }
  if (t && (t.endsWith('-removed') || t === 'schema-removed')) return 'breaking';
  return 'informational';
}

export function formatChanges(changes, options = {}) {
  const wantJson = options?.format === 'json' || options?.style === 'json' || options?.json === true;
  if (!Array.isArray(changes)) return '';
  if (wantJson) return JSON.stringify(changes, null, 2);
  if (changes.length === 0) return 'No changes detected.';
  return changes.map((c) => formatChangeText(c)).join('\n');
}
